import{_ as s,a,o as e,Q as t}from"./chunks/framework.D0YZUKpL.js";const i="/assets/icon.B61cb5X9.png",r="/assets/build.DDiguZOE.png",n="/assets/test.Cx0AA-CR.png",l="/assets/project.B4IGhmKD.png",p="/assets/test1.boCO3QVt.png",o="/assets/testProject.B-dvcbD2.png",h="/assets/testProject1.DQzC78z1.png",c="/assets/testResult.BxW2zMSa.png",d="/assets/cover.CnX41fV4.png",y=JSON.parse('{"title":"JavaScript 持续集成","description":"","frontmatter":{"title":"JavaScript 持续集成","date":"2017-09-29T01:25:18.000Z","tags":["JavaScript","Coveralls","Travis CI"],"license":"CC BY-NC 4.0","read":{"text":"4 min read","minutes":3.075,"time":184500,"words":615}},"headers":[{"level":2,"title":"持续集成","slug":"持续集成","link":"#持续集成","children":[]},{"level":2,"title":"测试覆盖率","slug":"测试覆盖率","link":"#测试覆盖率","children":[]},{"level":2,"title":"项目地址","slug":"项目地址","link":"#项目地址","children":[]}],"relativePath":"posts/js-ci.md","filePath":"posts/js-ci.md"}'),k={name:"posts/js-ci.md"},g=t('<p>这篇文章的目标就是在 GitHub 上显示如下图标。当然不是简单的显示两张图片，而是显示当前项目的一些状态。</p><p><img src="'+i+'" alt="icon"></p><p>持续集成官网： <a href="https://travis-ci.org/" target="_blank" rel="noreferrer">Travis-ci</a> 测试覆盖率官网：<a href="https://coveralls.io/" target="_blank" rel="noreferrer">COVERALLS</a></p><p><img src="'+r+'" alt="Build 状态"></p><p><img src="'+n+'" alt="测试状态"></p><h2 id="持续集成" tabindex="-1">持续集成 <a class="header-anchor" href="#持续集成" aria-label="Permalink to &quot;持续集成&quot;">​</a></h2><p>如果项目中没有测试，那么就不需要包含测试覆盖率这一块。</p><p>首先创建一个简单的项目</p><p><img src="'+l+`" alt="项目"></p><p>那么第一步，当然是选择跟着<a href="https://docs.travis-ci.com/user/languages/javascript-with-nodejs/" target="_blank" rel="noreferrer">官方文档</a>走啦，先创建 <code>.travis.yml</code> 文件，查看 <code>node</code> 版本 <code>node -v</code>。然后填进去，我的是 8.5.0，所以我的文件是这样的：</p><div class="language-yml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yml</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">language</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">node_js</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">node_js</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;8&#39;</span></span></code></pre></div><p>然后 <code>git push</code> 到 GitHub ，然后刷新 Travis CI 的页面：</p><p><img src="`+p+'" alt="Test"></p><p>就这样，持续集成就 OK 了，是不是很简单，然后点击 passing 图标，选择 Markdown 写到 readme 里面就可以在 GitHub 上看到了。</p><h2 id="测试覆盖率" tabindex="-1">测试覆盖率 <a class="header-anchor" href="#测试覆盖率" aria-label="Permalink to &quot;测试覆盖率&quot;">​</a></h2><p>同样的，跟着<a href="https://coveralls.zendesk.com/hc/en-us/articles/201769715-Javascript-Node" target="_blank" rel="noreferrer">官方文档</a>上的第一个 <a href="https://github.com/nickmerwin/node-coveralls" target="_blank" rel="noreferrer">node-coveralls</a> 走。项目还是上面那个测试项目。</p><p>测试项目的目录：</p><p><img src="'+o+`" alt="测试项目"></p><p>在 <a href="https://github.com/nickmerwin/node-coveralls" target="_blank" rel="noreferrer">node-coveralls</a> 里面有很多钟方式，我选择 <a href="https://github.com/gotwarlost/istanbul" target="_blank" rel="noreferrer">Istanbul</a> + <a href="https://github.com/mochajs/mocha" target="_blank" rel="noreferrer">mocha</a>。</p><p>那么，第一步，当然是安装 <a href="https://github.com/gotwarlost/istanbul" target="_blank" rel="noreferrer">Istanbul</a> + <a href="https://github.com/mochajs/mocha" target="_blank" rel="noreferrer">mocha</a> 啦，当然还要安装 <a href="https://coveralls.io/" target="_blank" rel="noreferrer">coveralls</a></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>npm install mocha --save-dev #安装 mohca</span></span>
<span class="line"><span>npm install istanbul --save-dev #安装 istanbul</span></span>
<span class="line"><span>npm install coveralls --save-dev #安装 coveralls</span></span></code></pre></div><p>为了不把 node_module 上传到 GitHub ，所以还需要创建 \`.gitignore&#39; ，在里面添加 node_module 文件夹。</p><p>然后写测试，测试为：</p><p><img src="`+h+'" alt="测试项目"></p><p>修改 <code>package.json</code> 里面的 <code>test</code> 脚本为</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">istanbul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cover</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./node_modules/mocha/bin/_mocha</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --report</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lcovonly</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./coverage/lcov.info</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> ./node_modules/coveralls/bin/coveralls.js</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./coverage</span></span></code></pre></div><p>然后运行 <code>npm test</code> 命令，会提示一个错误，那个是因为没有在 `package.json&#39; 里面添加 repository 地址，可以忽略。</p><p><img src="'+c+'" alt="测试结果"></p><p>到这一步，就可以把项目 push 到 GitHub 上去了。然后刷新在 <a href="https://coveralls.io/" target="_blank" rel="noreferrer">COVERALLS</a> 上的项目的网页。</p><p><img src="'+d+'" alt="测试覆盖率"></p><p>就可以看到成功了！然后点击 EMBED 图标，选择 Markdown 复制到 readme 里面，就可以显示在 GitHub 上了。</p><p>关于 <a href="https://docs.travis-ci.com/user/languages/javascript-with-nodejs/" target="_blank" rel="noreferrer">Travis CI</a> 和 <a href="https://coveralls.zendesk.com/hc/en-us/articles/201769715-Javascript-Node" target="_blank" rel="noreferrer">COVERALLS</a> 的具体的配置。请参考相应的官网的说明。</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to &quot;项目地址&quot;">​</a></h2><p>本篇文章的项目的 GitHub 地址 ：<a href="https://github.com/cwxyz007/TravisTest" target="_blank" rel="noreferrer">Travis Test</a></p><p>到这里还不赶紧去 GitHub 上配置一波～。 如果本篇文章对你有帮助，为什么不点一波喜欢在走呢～</p>',35),m=[g];function u(_,v,b,f,C,F){return e(),a("div",null,m)}const B=s(k,[["render",u]]);export{y as __pageData,B as default};
